// Migration script: Move page builder content into products & solutions
const TOKEN = 'sks3YrmS3dSv4Eg0CPrCec0c0xy8Fh3tjNcJ8uqmGjx6CqiDTTrMYZrv7oZbHsiVuMdSrTJgaSDWaT0lkWzT6w5lyapsIKyxdzfdjvMut07HkWyjKLUoqz1b6e5nSRL31BFgABAMPNLZnl5REeBpKuOnt7OsK05tOB5KAG6hUCUAY1NcweSK';
const PROJECT = 'dnhjoqwl';
const DATASET = 'production';
const API = `https://${PROJECT}.api.sanity.io/v2024-01-01`;

async function query(groq, params = {}) {
  const url = new URL(`${API}/data/query/${DATASET}`);
  url.searchParams.set('query', groq);
  for (const [k, v] of Object.entries(params)) {
    url.searchParams.set(`$${k}`, JSON.stringify(v));
  }
  const res = await fetch(url, { headers: { Authorization: `Bearer ${TOKEN}` } });
  const data = await res.json();
  if (data.error) throw new Error(JSON.stringify(data.error));
  return data.result;
}

async function mutate(mutations) {
  const res = await fetch(`${API}/data/mutate/${DATASET}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${TOKEN}`,
    },
    body: JSON.stringify({ mutations }),
  });
  const data = await res.json();
  if (data.error) throw new Error(JSON.stringify(data.error));
  return data;
}

function k() { return Math.random().toString(36).slice(2, 14); }

// ─── FASE 3a: Move AB2500 from Pages to Product ───
async function migrateAB2500() {
  console.log('\n=== Migrating AB2500 from Pages to Product ===');
  const page = await query('*[_type=="page" && slug.current=="ab2500"][0]{sections, seo, seo_en}');
  if (!page?.sections?.length) { console.log('AB2500 page not found or no sections'); return; }
  
  await mutate([{
    patch: {
      id: 'product-ab2500',
      set: { sezioniPagina: page.sections, seo: page.seo, seo_en: page.seo_en }
    }
  }]);
  console.log(`✅ AB2500: ${page.sections.length} sections moved to product`);
}

// ─── FASE 3b: Move solutions from Pages to Solution docs ───
async function migrateSolutions() {
  console.log('\n=== Migrating Solutions from Pages ===');
  const solutionMap = {
    'etichette': 'solution-etichette',
    'packaging': 'solution-packaging',
    'shopper': 'solution-shopper',
    'labbratura': 'solution-labbratura',
  };
  
  for (const [slug, docId] of Object.entries(solutionMap)) {
    const page = await query('*[_type=="page" && slug.current==$slug][0]{sections, seo, seo_en}', { slug });
    if (!page?.sections?.length) { console.log(`${slug}: no sections found`); continue; }
    
    await mutate([{
      patch: {
        id: docId,
        set: { sezioniPagina: page.sections, seo: page.seo, seo_en: page.seo_en }
      }
    }]);
    console.log(`✅ ${slug}: ${page.sections.length} sections moved to solution`);
  }
  
  // Consumabili - needs a new solution doc since it doesn't exist
  const consumPage = await query('*[_type=="page" && slug.current=="consumabili"][0]{sections, seo, seo_en, title, title_en}');
  if (consumPage?.sections?.length) {
    // Check if solution-consumabili exists
    const existing = await query('*[_type=="solution" && slug.current=="consumabili"][0]{_id}');
    if (existing) {
      await mutate([{
        patch: {
          id: existing._id,
          set: { sezioniPagina: consumPage.sections, seo: consumPage.seo, seo_en: consumPage.seo_en }
        }
      }]);
    } else {
      await mutate([{
        create: {
          _id: 'solution-consumabili',
          _type: 'solution',
          title: consumPage.title || 'Consumabili e Ricambi',
          title_en: consumPage.title_en || 'Consumables & Spare Parts',
          slug: { _type: 'slug', current: 'consumabili' },
          category: 'etichette',
          order: 99,
          sezioniPagina: consumPage.sections,
          seo: consumPage.seo,
          seo_en: consumPage.seo_en,
        }
      }]);
    }
    console.log(`✅ consumabili: ${consumPage.sections.length} sections moved to solution`);
  }
}

